import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class SecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input in the response
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("User input: " + Encode.forHtml(userInput));
        out.println("</body>");
        out.println("</html>");

        // Properly closing the PrintWriter
        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
